code_context.update:
def update(self):

    if self.interacting:

        for event in pygame.event.get((pygame.KEYDOWN, pygame.MOUSEBUTTONDOWN)):
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_e:
                    self.page_index += 1
                    self.master.sounds["select"].play()
            if event.type == pygame.MOUSEBUTTONDOWN:
                if event.button == 1 and self.master.game.touch_btns_enabled:
                    if self.dialogue_box_rect.collidepoint(event.pos):
                        self.page_index += 1
                        self.master.sounds["select"].play()
                        return

        for f_id, pos in self.master.game.fingers.items():
            if self.master.game.fingers_prev.get(f_id) is None:
                if self.dialogue_box_rect.collidepoint(pos):
                    self.page_index += 1
                    self.master.sounds["select"].play()
    else:
        self.check_near()

code_context.run:
def run(self):

    self.music.run()

    self.fingers_prev = self.fingers.copy()
    for event in pygame.event.get((pygame.FINGERDOWN, pygame.FINGERUP, pygame.FINGERMOTION)):
        if not self.touch_btns_enabled: continue

        if event.type == pygame.FINGERDOWN:
            self.fingers[event.finger_id] = (event.x*W, event.y*H)
        if event.type == pygame.FINGERMOTION:
            self.fingers[event.finger_id] = (event.x*W, event.y*H)
        if event.type == pygame.FINGERUP:
            try:
                del self.fingers[event.finger_id]
            except KeyError: pass

    if self.paused:
        self.pause_menu.draw()
        self.pause_menu.update()
        return

    self.player.update()
    self.level.update()
    if self.transitioning is not None:
        self.update_transition()

    self.run_end_check()

    self.level.draw_bg()
    self.player.draw()
    self.level.draw_fg()

    if self.end_start and not self.CORRIDOR:
        self.screen.blit(self.vingette, (0, 0))

    if self.transitioning is not None:
        self.black_surf.set_alpha(int(self.fade_alpha))
        self.screen.blit(self.black_surf, (0, 0))

    if self.end_screen:
        self.screen.fill(0xb5737c)
        self.screen.blit(self.title_shadow, (self.title_rect.x-2, self.title_rect.y+2))
        self.screen.blit(self.title_surf, self.title_rect)

code_context.interact:
def interact(self, mouse_pos, click=False):

    if click and self.mouse_hover:
        if self.action != "start":self.master.sounds["click"].play()
        return self.action
    self.mouse_hover = self.detection_rect.collidepoint(mouse_pos)
    if self.mouse_hover:
        if not self.hover_sound_played:
            self.hover_sound_played = True
            self.master.sounds["soft_click"].play()
    else:self.hover_sound_played = False

code_context.process_events:
def process_events(self):

    if self.in_control:
        finger_down = False

        for event in pygame.event.get((pygame.KEYUP, pygame.KEYDOWN, pygame.MOUSEBUTTONDOWN)):
            if event.type == pygame.KEYUP:
                if event.key == pygame.K_SPACE:
                    self.JUMP_TIMER.stop()
                    self.can_jump = True
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_e:
                    self.master.game.level.dg_manager.check_interact()
                if event.key == pygame.K_ESCAPE:
                    self.master.game.pause_game()
                if event.key == pygame.K_t:
                    self.master.game.touch_btns_enabled = not self.master.game.touch_btns_enabled
                    if not self.master.game.touch_btns_enabled:
                        self.master.game.fingers.clear()
            if event.type == pygame.MOUSEBUTTONDOWN and event.button == 1\
                  and self.master.game.touch_btns_enabled:
                    self.master.game.level.dg_manager.check_interact(touch_pos=event.pos)
                    finger_down = True

        for f_id, pos in self.master.game.fingers.items():
            if self.master.game.fingers_prev.get(f_id) is None:
                self.master.game.level.dg_manager.check_interact(touch_pos=pos)
                finger_down = True
        if self.pause_btn.interact(finger_down):
            self.master.game.pause_game()

    elif self.transition_state == "sitting" and self.master.game.transitioning is None:

        for event in pygame.event.get((pygame.KEYDOWN, pygame.MOUSEBUTTONDOWN)):
            if event.type == pygame.KEYDOWN:
                if event.key in (pygame.K_d, pygame.K_a, pygame.K_e, pygame.K_SPACE, pygame.K_TAB):
                    self.transition_state = "to_stand"
                    self.anim_in

